+
+function queueMessage(message: PanelToBg) {
+  if (message.type === 'panel:ping') return
+  pendingByType.set(message.type, message)
+}
+
+function flushPending() {
+  if (!port) return
+  const order: PanelToBgType[] = [
+    'panel:ready',
+    'panel:setAuto',
+    'panel:setModel',
+    'panel:rememberUrl',
+    'panel:summarize',
+    'panel:openOptions',
+  ]
+  for (const type of order) {
+    const msg = pendingByType.get(type)
+    if (!msg) continue
+    try {
+      port.postMessage(msg)
+    } catch {
+      return
+    }
+  }
+  pendingByType.clear()
+}
+
+function connectPort() {
+  if (port) return
+  try {
+    port = chrome.runtime.connect({ name: 'panel' })
+  } catch {
+    scheduleReconnect()
+    return
+  }
+
+  reconnectAttempt = 0
+  port.onMessage.addListener(handleBgMessage)
+  port.onDisconnect.addListener(() => {
+    port = null
+    if (!streaming) setStatus('Reconnecting…')
+    scheduleReconnect()
+  })
+
+  flushPending()
+}
+
+function scheduleReconnect() {
+  if (port) return
+  if (reconnectTimer) return
+  const delayMs = Math.min(250 * 2 ** reconnectAttempt, 3_000)
+  reconnectAttempt = Math.min(reconnectAttempt + 1, 6)
+  reconnectTimer = window.setTimeout(() => {
+    reconnectTimer = null
+    connectPort()
+  }, delayMs)
 }

